20	// Config contains the protocol/client settings shared by providers that speak
21	// the OpenAI-compatible Chat Completions API.
22	type Config struct {
23		BaseURL string
24		APIKey  string
25		Headers map[string]string
26		// QuotaHeaderParser, when set, is called on every response to convert
27		// the response Header into a quotaheaders.Signal. The signal is then
28		// forwarded to QuotaSignalObserver. Different providers (OpenAI vs
29		// OpenRouter) use different parsers, so the protocol layer takes the
30		// parser as a function and stays provider-agnostic.
31		QuotaHeaderParser func(http.Header, time.Time) quotaheaders.Signal
32		// QuotaSignalObserver, when set together with QuotaHeaderParser, receives
33		// the parsed signal on every response. The service layer wires this to
34		// the provider quota state machine.
35		QuotaSignalObserver func(quotaheaders.Signal)
36		// RuntimeSignalObserver, when set, receives the raw response headers,
37		// request latency, and any terminal error for every provider response.
38		RuntimeSignalObserver func(http.Header, time.Duration, error)
39	}
40	
41	// Client wraps openai-go with agent-native request and response conversion.
42	type Client struct {
43		client *oai.Client
44	}
45	
46	// NewClient creates an OpenAI-compatible protocol client.
47	func NewClient(cfg Config) *Client {
48		opts := []option.RequestOption{
49			option.WithBaseURL(cfg.BaseURL),
50			option.WithMaxRetries(0),
51		}
52		if cfg.APIKey != "" {
53			opts = append(opts, option.WithAPIKey(cfg.APIKey))
54		} else {
55			opts = append(opts, option.WithAPIKey("not-needed"))
56		}
57		for k, v := range cfg.Headers {
58			opts = append(opts, option.WithHeader(k, v))
59		}
60		// SSE comment-frame filter must sit before the debug sink so the sink
61		// observes the same byte stream the decoder will see. Middlewares are
62		// applied in registration order, outermost first.
63		opts = append(opts, option.WithMiddleware(SSEFilterMiddleware()))
64		if s := ResolveDebugSink(); s != nil {
65			opts = append(opts, option.WithMiddleware(DebugMiddleware(s)))
66		}
67		if cfg.QuotaHeaderParser != nil && cfg.QuotaSignalObserver != nil {
68			opts = append(opts, option.WithMiddleware(quotaHeaderMiddleware(cfg.QuotaHeaderParser, cfg.QuotaSignalObserver)))
69		}
70		if cfg.RuntimeSignalObserver != nil {
71			opts = append(opts, option.WithMiddleware(runtimeSignalMiddleware(cfg.RuntimeSignalObserver)))
72		}
73	
74		client := oai.NewClient(opts...)
75		return &Client{client: &client}
76	}
