78	// quotaHeaderMiddleware returns a middleware that runs `parser` on every
79	// response Header and forwards the resulting Signal to `observer`. The
80	// middleware is a no-op when the upstream call returns an error before a
81	// Response is produced, and runs *after* the response has been received but
82	// *before* the SDK consumes its body — both branches still surface the same
83	// (resp, err) tuple to the caller.
84	func quotaHeaderMiddleware(parser func(http.Header, time.Time) quotaheaders.Signal, observer func(quotaheaders.Signal)) option.Middleware {
85		return func(req *http.Request, next option.MiddlewareNext) (*http.Response, error) {
86			resp, err := next(req)
87			if resp != nil {
88				signal := parser(resp.Header, time.Now())
89				if signal.Present {
90					observer(signal)
91				}
92			}
93			return resp, err
94		}
95	}
96	
97	func runtimeSignalMiddleware(observer func(http.Header, time.Duration, error)) option.Middleware {
98		return func(req *http.Request, next option.MiddlewareNext) (*http.Response, error) {
99			start := time.Now()
100			resp, err := next(req)
101			if observer != nil {
102				var headers http.Header
103				if resp != nil {
104					headers = resp.Header
105				}
106				observer(headers, time.Since(start), err)
107			}
108			return resp, err
109		}
110	}
