112	// RequestOptions are request controls that map directly to the compatible Chat
113	// Completions wire shape. ExtraOptions carries provider-owned extensions such
114	// as non-standard reasoning/thinking fields.
115	type RequestOptions struct {
116		MaxTokens int
117		// Temperature/TopP/TopK/MinP/RepetitionPenalty are sampling controls.
118		// TopP is OpenAI-standard; TopK / MinP / RepetitionPenalty are
119		// non-standard OpenAI-compat extras that omlx, lmstudio, vLLM, and
120		// llama.cpp accept as top-level body fields. Nil means unset
121		// (server default applies). RepetitionPenalty > 1.0 prevents
122		// exact-token loops.
123		Temperature       *float64
124		TopP              *float64
125		TopK              *int
126		MinP              *float64
127		RepetitionPenalty *float64
128		Seed              int64
129		Stop              []string
130		ExtraOptions      []option.RequestOption
131		// CachePolicy mirrors agent.Options.CachePolicy. The OpenAI-compatible
132		// protocol layer does not act on it today; it is plumbed so a future
133		// caching-aware OpenAI-style provider has a typed field to consume.
134		CachePolicy string
135	}
