137	// ChatResult is a protocol-level non-streaming response without provider
138	// identity metadata.
139	type ChatResult struct {
140		Model        string
141		Content      string
142		FinishReason string
143		ToolCalls    []agent.ToolCall
144		Usage        agent.TokenUsage
145		RawUsage     string
146	}
147	
148	// CostHook extracts provider-owned cost data from a raw usage object. The SDK
149	// only calls the hook; it does not know provider-specific attribution rules.
150	type CostHook func(rawUsage string) *agent.CostAttribution
151	
152	// StreamAttemptHook builds provider-owned final attempt metadata for a stream.
153	type StreamAttemptHook func(responseModel string, cost *agent.CostAttribution) *agent.AttemptMetadata
154	
155	// StreamHooks are optional provider callbacks used by streaming conversion.
156	type StreamHooks struct {
157		Cost    CostHook
158		Attempt StreamAttemptHook
159	}
