161	// Chat executes one non-streaming Chat Completions request.
162	func (c *Client) Chat(ctx context.Context, model string, messages []agent.Message, tools []agent.ToolDef, opts RequestOptions) (ChatResult, error) {
163		params := buildParams(model, messages, tools, opts)
164		completion, err := c.client.Chat.Completions.New(ctx, params, opts.ExtraOptions...)
165		if err != nil {
166			return ChatResult{}, err
167		}
168	
169		result := ChatResult{
170			Model:    completion.Model,
171			RawUsage: completion.Usage.RawJSON(),
172		}
173		msgReasoningContent := extractMessageReasoningContent(completion.RawJSON())
174		if completion.Usage.TotalTokens != 0 {
175			result.Usage = tokenUsage(
176				int(completion.Usage.PromptTokens),
177				int(completion.Usage.CompletionTokens),
178				int(completion.Usage.TotalTokens),
179				int(completion.Usage.PromptTokensDetails.CachedTokens),
180			)
181			result.Usage.Reasoning, result.Usage.ReasoningTokensApprox = extractReasoningTokens(result.RawUsage, msgReasoningContent)
182		}
183	
184		if len(completion.Choices) > 0 {
185			choice := completion.Choices[0]
186			result.Content = choice.Message.Content
187			result.FinishReason = string(choice.FinishReason)
188			result.ToolCalls = extractToolCalls(choice.Message.ToolCalls)
189		}
190	
191		return result, nil
192	}
