194	// ChatStream executes one streaming Chat Completions request and converts
195	// chunks into agent stream deltas.
196	func (c *Client) ChatStream(ctx context.Context, model string, messages []agent.Message, tools []agent.ToolDef, opts RequestOptions, hooks StreamHooks) (<-chan agent.StreamDelta, error) {
197		params := buildParams(model, messages, tools, opts)
198		params.StreamOptions = oai.ChatCompletionStreamOptionsParam{
199			IncludeUsage: oai.Bool(true),
200		}
201	
202		stream := c.client.Chat.Completions.NewStreaming(ctx, params, opts.ExtraOptions...)
203	
204		ch := make(chan agent.StreamDelta, 1)
205		go func() {
206			defer close(ch)
207			send := func(delta agent.StreamDelta) {
208				delta.ArrivedAt = time.Now()
209				ch <- delta
210			}
211	
212			// OpenAI only sends tool call ID in the first chunk for each index;
213			// subsequent argument chunks carry the index but have an empty ID.
214			indexToID := make(map[int]string)
215			responseModel := model
216			var streamCost *agent.CostAttribution
217			var aggReasoningContent strings.Builder
218			for stream.Next() {
219				chunk := stream.Current()
220				if chunk.Model != "" {
221					responseModel = chunk.Model
222				}
223				if hooks.Cost != nil {
224					if cost := hooks.Cost(chunk.Usage.RawJSON()); cost != nil {
225						streamCost = cost
226					}
227				}
228	
229				reasoningContent := extractReasoningContent(chunk.RawJSON())
230				if reasoningContent != "" {
231					aggReasoningContent.WriteString(reasoningContent)
232				}
233	
234				if len(chunk.Choices) > 0 {
235					choice := chunk.Choices[0]
236	
237					for _, tc := range choice.Delta.ToolCalls {
238						id := tc.ID
239						if id != "" {
240							indexToID[int(tc.Index)] = id
241						} else {
242							id = indexToID[int(tc.Index)]
243						}
244						send(agent.StreamDelta{
245							Model:        chunk.Model,
246							ToolCallID:   id,
247							ToolCallName: tc.Function.Name,
248							ToolCallArgs: tc.Function.Arguments,
249						})
250					}
251	
252					if choice.Delta.Content != "" || choice.FinishReason != "" || reasoningContent != "" {
253						send(agent.StreamDelta{
254							Model:            chunk.Model,
255							Content:          choice.Delta.Content,
256							ReasoningContent: reasoningContent,
257							FinishReason:     string(choice.FinishReason),
258						})
259					} else if len(choice.Delta.ToolCalls) == 0 {
260						send(agent.StreamDelta{
261							Model:        chunk.Model,
262							FinishReason: string(choice.FinishReason),
263						})
264					}
265				} else {
266					send(agent.StreamDelta{Model: chunk.Model})
267				}
268	
269				if chunk.Usage.TotalTokens != 0 {
270					usage := tokenUsage(
271						int(chunk.Usage.PromptTokens),
272						int(chunk.Usage.CompletionTokens),
273						int(chunk.Usage.TotalTokens),
274						int(chunk.Usage.PromptTokensDetails.CachedTokens),
275					)
276					usage.Reasoning, usage.ReasoningTokensApprox = extractReasoningTokens(chunk.Usage.RawJSON(), aggReasoningContent.String())
277					send(agent.StreamDelta{Usage: &usage})
278				}
279			}
280	
281			if err := stream.Err(); err != nil {
282				send(agent.StreamDelta{Err: classifyStreamErr(err)})
283				return
284			}
285	
286			done := agent.StreamDelta{
287				Model: responseModel,
288				Done:  true,
289			}
290			if hooks.Attempt != nil {
291				done.Attempt = hooks.Attempt(responseModel, streamCost)
292			}
293			send(done)
294		}()
295	
296		return ch, nil
297	}
