299	func buildParams(model string, messages []agent.Message, tools []agent.ToolDef, opts RequestOptions) oai.ChatCompletionNewParams {
300		params := oai.ChatCompletionNewParams{
301			Model:    model,
302			Messages: convertMessages(messages),
303		}
304		if len(tools) > 0 {
305			params.Tools = convertTools(tools)
306		}
307		if opts.MaxTokens > 0 {
308			params.MaxTokens = oai.Int(int64(opts.MaxTokens))
309		}
310		if opts.Temperature != nil {
311			params.Temperature = oai.Float(*opts.Temperature)
312		}
313		if opts.TopP != nil {
314			params.TopP = oai.Float(*opts.TopP)
315		}
316		if opts.Seed != 0 {
317			params.Seed = oai.Int(opts.Seed)
318		}
319		if len(opts.Stop) > 0 {
320			params.Stop = oai.ChatCompletionNewParamsStopUnion{OfStringArray: opts.Stop}
321		}
322		return params
323	}
324	
325	func convertMessages(msgs []agent.Message) []oai.ChatCompletionMessageParamUnion {
326		var result []oai.ChatCompletionMessageParamUnion
327		for _, m := range msgs {
328			switch m.Role {
329			case agent.RoleSystem:
330				result = append(result, oai.SystemMessage(m.Content))
331			case agent.RoleUser:
332				result = append(result, oai.UserMessage(m.Content))
333			case agent.RoleAssistant:
334				if len(m.ToolCalls) > 0 {
335					var toolCalls []oai.ChatCompletionMessageToolCallParam
336					for _, tc := range m.ToolCalls {
337						toolCalls = append(toolCalls, oai.ChatCompletionMessageToolCallParam{
338							ID: tc.ID,
339							Function: oai.ChatCompletionMessageToolCallFunctionParam{
340								Name:      tc.Name,
341								Arguments: string(tc.Arguments),
342							},
343						})
344					}
345					assistant := oai.ChatCompletionAssistantMessageParam{
346						Content: oai.ChatCompletionAssistantMessageParamContentUnion{
347							OfString: param.NewOpt(m.Content),
348						},
349						ToolCalls: toolCalls,
350					}
351					result = append(result, oai.ChatCompletionMessageParamUnion{OfAssistant: &assistant})
352				} else {
353					result = append(result, oai.AssistantMessage(m.Content))
354				}
355			case agent.RoleTool:
356				result = append(result, oai.ToolMessage(m.Content, m.ToolCallID))
357			}
358		}
359		return result
360	}
361	
362	func convertTools(tools []agent.ToolDef) []oai.ChatCompletionToolParam {
363		var result []oai.ChatCompletionToolParam
364		for _, t := range tools {
365			var params map[string]interface{}
366			_ = json.Unmarshal(t.Parameters, &params)
367	
368			result = append(result, oai.ChatCompletionToolParam{
369				Function: oai.FunctionDefinitionParam{
370					Name:        t.Name,
371					Description: oai.String(t.Description),
372					Parameters:  oai.FunctionParameters(params),
373				},
374			})
375		}
376		return result
377	}
378	
379	func extractToolCalls(calls []oai.ChatCompletionMessageToolCall) []agent.ToolCall {
380		if len(calls) == 0 {
381			return nil
382		}
383		var result []agent.ToolCall
384		for _, c := range calls {
385			result = append(result, agent.ToolCall{
386				ID:        c.ID,
387				Name:      c.Function.Name,
388				Arguments: json.RawMessage(c.Function.Arguments),
389			})
390		}
391		return result
392	}
393	
394	func extractReasoningContent(rawJSON string) string {
395		if rawJSON == "" {
396			return ""
397		}
398		var raw struct {
399			Choices []struct {
400				Delta struct {
401					ReasoningContent string `json:"reasoning_content"`
402				} `json:"delta"`
403			} `json:"choices"`
404		}
405		if err := json.Unmarshal([]byte(rawJSON), &raw); err != nil || len(raw.Choices) == 0 {
406			return ""
407		}
408		return raw.Choices[0].Delta.ReasoningContent
409	}
410	
411	func tokenUsage(input, output, total, cacheRead int) agent.TokenUsage {
412		usage := agent.TokenUsage{
413			Input:  input,
414			Output: output,
415			Total:  total,
416		}
417		if cacheRead > 0 {
418			usage.CacheRead = cacheRead
419		}
420		return usage
421	}
