423	// extractReasoningTokens resolves the reasoning token count per ADR-010
424	// Amendment §8. Resolution chain:
425	//  1. usage.completion_tokens_details.reasoning_tokens (authoritative; even
426	//     an explicit zero is honoured — the provider signalled no reasoning ran).
427	//  2. Top-level usage.reasoning_tokens > 0 (non-standard servers).
428	//  3. char-count(reasoningContent)÷4 when the usage path is absent AND
429	//     reasoningContent is non-empty. Returns approx=true.
430	//
431	// The char-count/4 estimator is a v1 placeholder (4 chars ≈ 1 token for
432	// English; accuracy degrades for CJK or heavily-symbolic content). A future
433	// bead can replace it with a real tokenizer once measurement shows the
434	// approximation error matters in practice.
435	//
436	// Returns (tokens, approx). approx is true only in case 3.
437	func extractReasoningTokens(rawUsageJSON, reasoningContent string) (int, bool) {
438		if rawUsageJSON == "" {
439			if reasoningContent != "" {
440				return len(reasoningContent) / 4, true
441			}
442			return 0, false
443		}
444		var raw struct {
445			CompletionTokensDetails struct {
446				// Pointer so absent vs. explicit-zero are distinguishable: nil means
447				// the field was not present; &0 means the server said "no reasoning".
448				ReasoningTokens *int `json:"reasoning_tokens"`
449			} `json:"completion_tokens_details"`
450			// Some non-OpenAI servers put reasoning_tokens at the top level.
451			ReasoningTokens *int `json:"reasoning_tokens,omitempty"`
452		}
453		if err := json.Unmarshal([]byte(rawUsageJSON), &raw); err != nil {
454			return 0, false
455		}
456		if raw.CompletionTokensDetails.ReasoningTokens != nil {
457			// Field present — respect the value even if zero (provider said no
458			// reasoning ran; do not fall through to the char-count heuristic).
459			return *raw.CompletionTokensDetails.ReasoningTokens, false
460		}
461		if raw.ReasoningTokens != nil && *raw.ReasoningTokens > 0 {
462			return *raw.ReasoningTokens, false
463		}
464		// usage path absent; fall back to reasoning_content char-count estimate.
465		if reasoningContent != "" {
466			return len(reasoningContent) / 4, true
467		}
468		return 0, false
469	}
470	
471	// extractMessageReasoningContent reads choices[0].message.reasoning_content
472	// from a full (non-streaming) Chat Completions response JSON. Providers that
473	// do thinking inline but do not populate completion_tokens_details (e.g. ds4)
474	// carry the thinking text here. Returns "" when absent or unparseable.
475	func extractMessageReasoningContent(rawCompletionJSON string) string {
476		if rawCompletionJSON == "" {
477			return ""
478		}
479		var raw struct {
480			Choices []struct {
481				Message struct {
482					ReasoningContent string `json:"reasoning_content"`
483				} `json:"message"`
484			} `json:"choices"`
485		}
486		if err := json.Unmarshal([]byte(rawCompletionJSON), &raw); err != nil || len(raw.Choices) == 0 {
487			return ""
488		}
489		return raw.Choices[0].Message.ReasoningContent
490	}
