1	// Package openai implements a agent.Provider for any OpenAI-compatible API
2	// endpoint (LM Studio, Ollama, OpenAI, Azure, Groq, Together, OpenRouter).
3	package openai
4	
5	import (
6		"context"
7		"fmt"
8		"log/slog"
9		"net/http"
10		"net/url"
11		"strconv"
12		"strings"
13		"sync"
14		"time"
15	
16		agent "github.com/easel/fizeau/internal/core"
17		"github.com/easel/fizeau/internal/provider/quotaheaders"
18		reasoningpolicy "github.com/easel/fizeau/internal/reasoning"
19		"github.com/easel/fizeau/internal/runtimesignals"
20		"github.com/easel/fizeau/internal/sdk/openaicompat"
21		"github.com/openai/openai-go/option"
22	)
23	
24	// Provider implements agent.Provider for OpenAI-compatible APIs.
25	type Provider struct {
26		client             *openaicompat.Client
27		model              string
28		modelPattern       string            // regex filter for auto-discovery; "" means first model
29		knownModels        map[string]string // catalog-recognized model IDs (modelID → catalogRef)
30		baseURL            string            // stored for lazy model discovery
31		apiKey             string            // stored for lazy model discovery
32		providerName       string
33		providerSystem     string
34		capabilities       *ProtocolCapabilities
35		usageCost          func(rawUsage string) (*agent.CostAttribution, bool)
36		serverAddress      string
37		serverPort         int
38		reasoningDefault   reasoningpolicy.Reasoning
39		modelReasoningWire map[string]string
40		logger             *slog.Logger
41	
42		// lazy model discovery — runs at most once per Provider instance
43		discoverOnce     sync.Once
44		discoverErr      error
45		discoveredModels []ScoredModel // full ranked list; populated on first use when model == ""
46	}
47	
48	// Config holds configuration for the OpenAI-compatible provider.
49	type Config struct {
50		BaseURL      string // e.g., "http://localhost:1234/v1" for LM Studio
51		APIKey       string // optional for local providers
52		Model        string // e.g., "qwen3.5-7b", "gpt-4o". Empty = auto-discover.
53		ProviderName string // logical provider identity; default "openai"
54		// ProviderSystem is the telemetry/cost system identity. When empty, it
55		// defaults to "openai". Concrete provider wrappers set their own type.
56		ProviderSystem string
57		ModelPattern   string // case-insensitive regex to prefer among auto-discovered models
58		// KnownModels maps concrete model IDs to catalog target IDs for the
59		// agent.openai surface. Models present in this map are ranked higher during
60		// auto-selection. Populated by the config layer from the model catalog;
61		// nil disables catalog-aware ranking.
62		KnownModels map[string]string
63		Headers     map[string]string // extra HTTP headers (OpenRouter, Azure, etc.)
64		Reasoning   reasoningpolicy.Reasoning
65		// Capabilities supplies provider-owned protocol capability claims. When nil,
66		// direct openai.Provider callers use OpenAI protocol defaults.
67		Capabilities *ProtocolCapabilities
68		// UsageCostAttribution extracts provider-owned gateway cost metadata from
69		// the raw usage object, when that provider reports one.
70		UsageCostAttribution func(rawUsage string) (*agent.CostAttribution, bool)
71		// ModelReasoningWire maps a concrete model ID to the catalog
72		// reasoning_wire value for that model. Recognized values are "provider"
73		// (default), "model_id" (model name encodes reasoning level — strip the
74		// reasoning field at serialization), "none" (model has no reasoning
75		// surface — reject explicit non-off requests pre-flight), "effort"
76		// (always emit reasoning.effort string), and "tokens" (always emit
77		// reasoning.max_tokens int). Models not listed default to "provider",
78		// preserving existing behavior.
79		ModelReasoningWire map[string]string
80		// Logger is used for structured diagnostic logging. When nil, slog.Default() is used.
81		Logger *slog.Logger
82		// QuotaHeaderParser, when set, overrides the default OpenAI rate-limit
83		// header parser. OpenRouter uses this to install
84		// quotaheaders.ParseOpenRouter even though it goes through this
85		// OpenAI-compatible provider implementation.
86		QuotaHeaderParser func(http.Header, time.Time) quotaheaders.Signal
87		// QuotaSignalObserver receives parsed rate-limit signals on every
88		// response. The service layer wires this to the provider quota state
89		// machine. Both QuotaHeaderParser and QuotaSignalObserver must be set
90		// for header-driven exhaustion tracking to activate.
91		QuotaSignalObserver func(quotaheaders.Signal)
92	}
93	
94	// New creates a new OpenAI-compatible provider.
95	func New(cfg Config) *Provider {
96		serverAddress, serverPort := endpointMetadata(cfg.BaseURL)
97		providerSystem := "openai"
98		if cfg.ProviderSystem != "" {
99			providerSystem = cfg.ProviderSystem
100		}
101		providerName := cfg.ProviderName
102		if providerName == "" {
103			providerName = providerSystem
104		}
105		parser := cfg.QuotaHeaderParser
106		if parser == nil && cfg.QuotaSignalObserver != nil {
107			// Default to OpenAI-shaped header parsing when no explicit parser is
108			// supplied. OpenRouter overrides this via Config.QuotaHeaderParser.
109			parser = quotaheaders.ParseOpenAI
110		}
111		runtimeObserver := func(headers http.Header, latency time.Duration, callErr error) {
112			runtimesignals.RecordResponse(providerName, headers, latency, providerSystem)
