167	// resolveModel returns the model to use for a request. If the provider was
168	// configured without a model it queries /v1/models once, ranks results, and
169	// caches both the full list and the selected model.
170	// Subsequent calls return the cached value without hitting the network.
171	func (p *Provider) resolveModel(ctx context.Context) (string, error) {
172		if p.model != "" {
173			return p.model, nil
174		}
175		p.discoverOnce.Do(func() {
176			candidates, err := DiscoverModels(ctx, p.baseURL, p.apiKey)
177			if err != nil {
178				p.discoverErr = err
179				return
180			}
181			ranked, err := RankModels(candidates, p.knownModels, p.modelPattern)
182			if err != nil {
183				p.discoverErr = err
184				return
185			}
186			p.discoveredModels = ranked
187			selected := SelectModel(ranked)
188			if selected == "" {
189				p.discoverErr = fmt.Errorf("openai: no models returned by %s/models", p.baseURL)
190				return
191			}
192			p.model = selected
193		})
194		return p.model, p.discoverErr
195	}
