267	// compatRequestOptions is the canonical openai-compat wire-field assembler
268	// and, per ADR-007 §3, the architectural home for any future
269	// (model_family × reasoning_state × profile) sampling-composition rule.
270	// Reasoning policy and the resolved sampling profile both reach this seam;
271	// when a profile field needs to be clipped or substituted because the
272	// model is in a thinking state (or vice-versa), the rule lives here — not
273	// in the resolver, not in the catalog.
274	//
275	// v1 ships without an active composition rule. The seeded "code" profile
276	// (T=0.6, top_p=0.95, top_k=20) matches Qwen3.x's published thinking-mode
277	// precise-coding recommendation exactly, and is also non-greedy enough to
278	// be safe in the non-thinking-mode case. When a future profile adds a
279	// value that diverges between thinking and non-thinking states for some
280	// family, add the clip rule here; for now, all five sampler fields pass
281	// through unchanged regardless of reasoning state.
282	func (p *Provider) compatRequestOptions(model string, opts agent.Options) (openaicompat.RequestOptions, reasoningpolicy.Reasoning, error) {
283		extra, reasoningEmitted, err := p.reasoningRequestOptions(model, opts)
284		if err != nil {
285			return openaicompat.RequestOptions{}, "", err
286		}
287		temperature := opts.Temperature
288		topP := opts.TopP
289		if nativeOpenAIUsesDefaultSamplingOnly(p.providerSystem, model) {
290			temperature = nil
291			topP = nil
292		}
293		// Non-standard sampling fields (top_k, min_p, repetition_penalty) ride
294		// as top-level body extras on OpenAI-compatible local/provider wires.
295		// OpenAI proper rejects these as unknown parameters, so only send them
296		// to compatibility providers that are known to accept them.
297		if p.providerSystem != "openai" {
298			if opts.TopK != nil {
299				extra = append(extra, option.WithJSONSet("top_k", *opts.TopK))
300			}
301			if opts.MinP != nil {
302				extra = append(extra, option.WithJSONSet("min_p", *opts.MinP))
303			}
304			if opts.RepetitionPenalty != nil {
305				extra = append(extra, option.WithJSONSet("repetition_penalty", *opts.RepetitionPenalty))
306			}
307		}
308		return openaicompat.RequestOptions{
309			MaxTokens:         opts.MaxTokens,
310			Temperature:       temperature,
311			TopP:              topP,
312			TopK:              opts.TopK,
313			MinP:              opts.MinP,
314			RepetitionPenalty: opts.RepetitionPenalty,
315			Seed:              opts.Seed,
316			Stop:              opts.Stop,
317			ExtraOptions:      extra,
318			CachePolicy:       opts.CachePolicy,
319		}, reasoningEmitted, nil
320	}
