354	func applyReasoningAliasMap(policy reasoningpolicy.Policy, aliasMap map[string]string) (reasoningpolicy.Policy, bool) {
355		if policy.Kind != reasoningpolicy.KindNamed || len(aliasMap) == 0 {
356			return policy, false
