368	// reasoningRequestOptions builds per-request options. For thinking models
369	// (Qwen3, DeepSeek-R1 etc.) apply provider-specific non-standard body fields
370	// only when the concrete provider declares the matching wire support.
371	func (p *Provider) reasoningRequestOptions(model string, opts agent.Options) ([]option.RequestOption, reasoningpolicy.Reasoning, error) {
372		policy, err := reasoningpolicy.Parse(opts.Reasoning)
373		if err != nil {
374			return nil, "", err
375		}
376		explicitRequest := policy.IsSet()
377		if !explicitRequest {
378			policy, err = reasoningpolicy.Parse(p.reasoningDefault)
379			if err != nil {
380				return nil, "", err
381			}
382		}
383	
384		if !policy.IsSet() || policy.Kind == reasoningpolicy.KindAuto {
385			return nil, "", nil
386		}
387	
388		// Catalog reasoning_wire metadata gates the wire shape before any
389		// provider-specific encoding runs. Models flagged as reasoning_wire=none
390		// have no reasoning surface at all; an explicit non-off request is a
391		// catalog/wire mismatch and must surface as an error rather than be
392		// silently dropped. Models flagged as reasoning_wire=model_id encode the
393		// reasoning level in the model name (e.g. fixed-variant Qwen3.6) and the
394		// upstream endpoint cannot honor an external reasoning toggle, so the
395		// reasoning field must be stripped from the wire body.
396		catalogWire := p.modelReasoningWireFor(model)
397		switch catalogWire {
398		case "none":
399			if explicitRequest && !policy.IsExplicitOff() {
400				return nil, "", fmt.Errorf("openai: model %q has reasoning_wire=none; explicit reasoning=%q is not supported", model, policy.Value)
401			}
402			return nil, "", nil
403		case "model_id":
404			return nil, "", nil
405		}
406	
407		if !p.SupportsThinking() {
408			if policy.IsExplicitOff() {
409				return nil, reasoningpolicy.ReasoningOff, nil
410			}
411			if explicitRequest {
412				return nil, "", fmt.Errorf("openai: reasoning=%q is not supported by provider type %q", policy.Value, p.providerSystem)
413			}
414			return nil, "", nil
415		}
416	
417		if policy.IsExplicitOff() {
418			switch p.thinkingWireFormat() {
419			case ThinkingWireFormatQwen:
420				if !isQwenModel(model) {
421					if explicitRequest && p.strictThinkingModelMatch() {
422						return nil, "", fmt.Errorf("openai: qwen reasoning control is not supported for model %q on provider type %q", model, p.providerSystem)
423					}
424					return nil, "", nil
425				}
426				return []option.RequestOption{
427					option.WithJSONSet("chat_template_kwargs", map[string]interface{}{
428						"enable_thinking": false,
429					}),
430				}, reasoningpolicy.ReasoningOff, nil
431			case ThinkingWireFormatOpenRouter:
432				return []option.RequestOption{option.WithJSONSet("reasoning", map[string]interface{}{
433					"effort": "none",
434				})}, reasoningpolicy.ReasoningOff, nil
435			case ThinkingWireFormatOpenAIEffort:
436				return []option.RequestOption{option.WithJSONSet("think", false)}, reasoningpolicy.ReasoningOff, nil
437			}
438			return nil, reasoningpolicy.ReasoningOff, nil
439		}
440	
441		if p.thinkingWireFormat() == ThinkingWireFormatOpenRouter {
442			return openRouterReasoningOptions(policy, model, catalogWire)
443		}
444		if p.thinkingWireFormat() == ThinkingWireFormatOpenAIEffort {
445			return openAIEffortReasoningOptions(policy, p.protocolCapabilities().ReasoningAliasMap, p.logger, model, p.providerSystem)
446		}
447		if p.thinkingWireFormat() == ThinkingWireFormatQwen && !isQwenModel(model) {
448			if explicitRequest && p.strictThinkingModelMatch() {
449				return nil, "", fmt.Errorf("openai: qwen reasoning control is not supported for model %q on provider type %q", model, p.providerSystem)
450			}
451			return nil, "", nil
452		}
453	
454		// Qwen and ThinkingMap providers can only express a token budget on the
455		// wire. If the catalog declares effort wire for this model, degrade
456		// gracefully: snap KindTokens to the nearest PortableBudgets tier so the
457		// downstream budget calculation uses a standard value. The model still
458		// works; the catalog entry is simply mis-classified.
459		if catalogWire == "effort" {
460			p.logger.Warn("catalog declares effort wire but provider only supports budget wire",
461				"model", model,
462				"provider", p.providerSystem,
463			)
464			if policy.Kind == reasoningpolicy.KindTokens {
465				tier := reasoningpolicy.NearestTierForTokens(policy.Tokens)
466				policy = reasoningpolicy.Policy{Kind: reasoningpolicy.KindNamed, Value: tier}
467			}
468		}
469	
470		thinkingBudget, err := reasoningpolicy.BudgetFor(policy, nil, 0)
471		if err != nil {
472			return nil, "", fmt.Errorf("openai: %w", err)
473		}
474		if thinkingBudget <= 0 {
475			return nil, "", nil
476		}
477		emitted := reasoningpolicy.ReasoningTokens(thinkingBudget)
478	
479		switch p.thinkingWireFormat() {
480		case ThinkingWireFormatQwen:
481			return []option.RequestOption{
482				option.WithJSONSet("chat_template_kwargs", map[string]interface{}{
483					"enable_thinking": true,
484					"thinking_budget": thinkingBudget,
485				}),
486			}, emitted, nil
487		case "", ThinkingWireFormatThinkingMap:
488			return []option.RequestOption{option.WithJSONSet("thinking", map[string]interface{}{
489				"type":          "enabled",
490				"budget_tokens": thinkingBudget,
491			})}, emitted, nil
492		default:
493			return nil, "", fmt.Errorf("openai: unsupported thinking wire format %q for provider type %q", p.thinkingWireFormat(), p.providerSystem)
494		}
495	}
