497	// openAIEffortReasoningOptions builds the flat top-level reasoning_effort wire
498	// used by ds4 / deepseek-v4-flash. Named tiers are emitted as-is; token
499	// budgets are snapped to the nearest PortableBudgets tier via NearestTierForTokens.
500	// Alias maps from live introspection are applied after snapping so ds4's
501	// low/medium/xhigh→high aliasing is reflected on the wire.
502	func openAIEffortReasoningOptions(policy reasoningpolicy.Policy, aliasMap map[string]string, logger *slog.Logger, model, providerSystem string) ([]option.RequestOption, reasoningpolicy.Reasoning, error) {
503		var tier reasoningpolicy.Reasoning
504		switch policy.Kind {
505		case reasoningpolicy.KindTokens:
506			tier = reasoningpolicy.NearestTierForTokens(policy.Tokens)
507		case reasoningpolicy.KindNamed:
508			tier = policy.Value
509		default:
510			return nil, "", fmt.Errorf("openai: unsupported OpenAI effort reasoning policy kind %q", policy.Kind)
511		}
512		normalized, changed := applyReasoningAliasMap(reasoningpolicy.Policy{Kind: reasoningpolicy.KindNamed, Value: tier}, aliasMap)
513		if changed && logger != nil {
514			logger.Warn("reasoning alias map overrode requested tier",
515				"model", model,
516				"provider", providerSystem,
517				"reasoning_intent", string(tier),
518				"reasoning_emitted", string(normalized.Value),
519				"reasoning_emitted_reason", providerSystem+" alias map",
520			)
521			tier = normalized.Value
522		}
523		return []option.RequestOption{option.WithJSONSet("reasoning_effort", string(tier))}, tier, nil
524	}
