542	// openRouterReasoningOptions builds the OpenRouter nested reasoning object.
543	// model is included for structured-warning logs.
544	// wire is the catalog reasoning_wire value for the model:
545	//   - "" or "provider": pick wire shape from policy.Kind (backwards-compat)
546	//   - "effort": always emit reasoning.effort string; snap KindTokens to nearest tier
547	//   - "tokens": always emit reasoning.max_tokens int; expand KindNamed via PortableBudgets
548	func openRouterReasoningOptions(policy reasoningpolicy.Policy, model, wire string) ([]option.RequestOption, reasoningpolicy.Reasoning, error) {
549		reasoning := map[string]interface{}{}
550		var emitted reasoningpolicy.Reasoning
551		switch wire {
552		case "effort":
553			var tier reasoningpolicy.Reasoning
554			switch policy.Kind {
555			case reasoningpolicy.KindTokens:
556				tier = reasoningpolicy.NearestTierForTokens(policy.Tokens)
557			case reasoningpolicy.KindNamed:
558				tier = policy.Value
559				if tier == reasoningpolicy.ReasoningMax {
560					tier = reasoningpolicy.ReasoningXHigh
561				}
562			default:
563				return nil, "", fmt.Errorf("openai: unsupported OpenRouter reasoning policy %q for effort wire", policy.Kind)
564			}
565			effort := string(tier)
566			switch effort {
567			case "minimal", "low", "medium", "high", "xhigh":
568				reasoning["effort"] = effort
569				emitted = tier
570			default:
571				return nil, "", fmt.Errorf("openai: unsupported OpenRouter reasoning effort %q", tier)
572			}
573		case "tokens":
574			var budget int
575			switch policy.Kind {
576			case reasoningpolicy.KindTokens:
577				budget = policy.Tokens
578			case reasoningpolicy.KindNamed:
579				budget = reasoningpolicy.BudgetForNamed(policy.Value)
580				if budget <= 0 {
581					return nil, "", fmt.Errorf("openai: named reasoning %q has no portable token budget for tokens wire", policy.Value)
582				}
583			default:
584				return nil, "", fmt.Errorf("openai: unsupported OpenRouter reasoning policy %q for tokens wire", policy.Kind)
585			}
586			reasoning["max_tokens"] = budget
587			emitted = reasoningpolicy.ReasoningTokens(budget)
588		default:
589			// "" or "provider": today's behavior — pick wire shape from policy.Kind.
590			switch policy.Kind {
591			case reasoningpolicy.KindTokens:
592				reasoning["max_tokens"] = policy.Tokens
593				emitted = reasoningpolicy.ReasoningTokens(policy.Tokens)
594			case reasoningpolicy.KindNamed:
595				effort := string(policy.Value)
596				if policy.Value == reasoningpolicy.ReasoningMax {
597					effort = string(reasoningpolicy.ReasoningXHigh)
598				}
599				switch effort {
600				case "minimal", "low", "medium", "high", "xhigh":
601					reasoning["effort"] = effort
602					emitted = reasoningpolicy.Reasoning(effort)
603				default:
604					return nil, "", fmt.Errorf("openai: unsupported OpenRouter reasoning effort %q", policy.Value)
605				}
606			default:
607				return nil, "", fmt.Errorf("openai: unsupported OpenRouter reasoning policy %q", policy.Kind)
608			}
609		}
610		return []option.RequestOption{option.WithJSONSet("reasoning", reasoning)}, emitted, nil
611	}
